// --- Input Handling ---
// Retrieve Contact data (from current input) and Ticket data (from lookup node)
const contactResponse = $input.item.json;
// Handle HubSpot API variations: 'results' array (Search API) vs direct object (Get API)
const contactProps = contactResponse.results ? contactResponse.results[0].properties : contactResponse.properties;

const ticketNode = $('HubSpot: Get Associations').item.json;
const ticketProps = ticketNode.properties;

// --- Property Extraction ---
const revenue = parseFloat(contactProps.annualrevenue || 0);
const stage = contactProps.lifecyclestage || "unknown";

const email = contactProps.email;
const subject = ticketProps.subject || "No Subject";
const message = ticketProps.content || "";

// --- Logic Thresholds ---
const isHighRevenue = revenue > 10000;
const isEnterprise = stage === 'evangelist' || stage === 'customer';

// Check for churn risk keywords in ticket content
const criticalKeywords = ["cancel", "refund", "expensive", "lawyer", "competitor", "broken"];
const isChurnRisk = criticalKeywords.some(keyword => message.toLowerCase().includes(keyword));

let severity = "Normal";
let owner = "support-general";

// --- Triage Logic ---
if (isHighRevenue && isChurnRisk) {
  severity = "CRITICAL";
  owner = "head-of-cs";
} else if (isHighRevenue) {
  severity = "High";
  owner = "senior-csm";
} else if (isChurnRisk) {
  severity = "High";
  owner = "retention-team";
}

// --- Output Payload ---
return {
  json: {
    subject: subject,
    customer_email: email,
    hubspot_revenue: revenue,
    hubspot_stage: stage,
    severity: severity,
    assigned_to: owner,
    timestamp: new Date().toISOString(),
    slack_message: `🚨 *${severity} TICKET* | ${email}\n> "${subject}"\n💰 ARR: $${revenue} (${stage})\n👉 Assignee: @${owner}`,
    jira_summary: `[${severity}] ${email} - ${subject}`
  }
};

